export async function transform({ input, createDocumentModel, createParagraph }) {
  const text = typeof input?.text === "string" ? input.text : "OFD document";
  return createDocumentModel({
    title: input?.title || "OFD Local Reader Patch",
    sourceFormat: "ofd-plugin",
    blocks: [createParagraph("OFD local reader patch accepted the document locally: " + text.slice(0, 120))],
    metadata: { plugin: { id: "ofd-local-reader", patch: true, localOnly: true } }
  });
}
